Here's a well-structured MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — a handler that delays long enough for cancellation to fire
        using var cts = new CancellationTokenSource();
        var handler = new DelayedHandler(TimeSpan.FromSeconds(30));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Cancel immediately
        cts.Cancel();

        // Act & Assert
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // test-level timeout via CancellationToken
    public async Task FetchAsync_SlowResponse_CancelledByTimeout()
    {
        var handler = new DelayedHandler(TimeSpan.FromSeconds(30));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // TestContext.CancellationToken fires when [Timeout] elapses
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    // --- Test doubles ---

    private sealed class FakeHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
            return Task.FromResult(response);
        }
    }

    private sealed class DelayedHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time elapses |
| `Assert.ThrowsExactlyAsync` | Tests exact exception type with better messages than `[ExpectedException]` |
| `Assert.ThrowsAsync` | Tests cancellation (catches `OperationCanceledException` **or** derived `TaskCanceledException`) |
| Custom `HttpMessageHandler` | Avoids real HTTP calls; controls responses and simulates delays |
| Sealed test class + sealed handlers | Performance and design clarity |

**Cancellation vs Timeout distinction:** Use `Assert.ThrowsAsync<OperationCanceledException>` (not `ThrowsExactly`) for cancellation because `HttpClient` may throw either `OperationCanceledException` or its subclass `TaskCanceledException`.
